export type InitialStateType = {
    isAoth: boolean,
    users: any,
}
const initialState: InitialStateType = {
    isAoth: false,
    users: [],
}

const authReducer = (state = initialState) => {
    let copy;
    async function api() {
        const request = await fetch("http://localhost:5000/api/users", {
            headers: {
                method: "GET",
                //@ts-ignore
                authorisation: JSON.parse(localStorage.getItem("user")).accessToken,
            }
        })
        if (request.status === 401) {
            console.log("Пользователь не авторизован");
            copy = { ...state, isAoth: false, users: a };
            return copy;
        }
        const response = await request.json();
        return response;
    }
    const a = api();
    copy = { ...state, isAoth: true, users: a };
    return copy;
};



export default authReducer;
